package.preload["bomb"] = function ()
    local bomb = {}
    local c_entity = require("entity")
    local vector = require("vector")
    local math   = require("mathx")
    local events = require("events")
    local planting_player = nil

    bomb.get_site = function () 
        local info = entity.get_all("CPlantedC4") 
        for index, value in ipairs(info) do 
            local bomb_info = c_entity.new(value) 
            if bomb_info.m_nBombSite == 0 then 
                return "A" 
            elseif bomb_info.m_nBombSite == 1 then 
                return "B" 
            end 
        end 
    end 
    bomb.get_time = function ()
        local info = entity.get_all("CPlantedC4") 
        for index, value in ipairs(info) do 
            local bomb_info = c_entity.new(value) 
            return string.format("%.1f", bomb_info.m_flC4Blow - globals.curtime()) 

        end 
    end 
    bomb.is_planted = function () 
        return entity.get_prop(entity.get_game_rules(),"m_bBombPlanted") 
    end 
    bomb.get_planting_time = function () 
        local info = entity.get_all("CC4") 
        for index, value in ipairs(info) do 
            local bomb_info = c_entity.new(value) 
            return string.format("%.1f", bomb_info.m_fArmedTime - globals.curtime() + 0.3) 
        end 
    end 
    bomb.is_getting_defused = function() 
        local info = entity.get_all("CPlantedC4") 
        for index, value in ipairs(info) do 
            local bomb_info = c_entity.new(value) 
            return string.format("%i", (bomb_info.m_hBombDefuser or 0)) == "1" 
        end 
    end
    bomb.get_is_planting = function() 
        local info = entity.get_all("CC4") 
        for index, value in ipairs(info) do 
            local bomb_info = c_entity.new(value) 
            return string.format("%i", bomb_info.m_bStartedArming) == "1" 
        end 
    end 
    bomb.get_defuse_time = function() 
        local info = entity.get_all("CPlantedC4") 
        for index, value in ipairs(info) do 
            local bomb_info = c_entity.new(value) 
            return string.format("%.1f", bomb_info.m_flDefuseCountDown - globals.curtime()) 
        end 
    end

    local damage_apply_armor = function(damage, armor_value)
        local armor_ratio = 0.5
        local armor_bonus = 0.5

        if armor_value > 0 then
            local flNew = damage * armor_ratio
            local flArmor = (damage - flNew) * armor_bonus

            if flArmor > armor_value then
                flArmor = armor_value * (1 / armor_bonus)
                flNew = damage - flArmor
            end

            damage = flNew
        end

        return damage
    end

    local calculate_damage = function(from_player, other, armor_value)
        local eye_position = vector(client.eye_position())
        local distance = eye_position:dist(vector(entity.get_origin(other)))
        local damage, fatal = 500, false
        local radius = damage * 3.5

        damage = damage * math.exp(-((distance * distance) / ((radius * 2 / 3) * (radius / 3))))
        damage = math.floor(damage_apply_armor(math.max(damage, 0), armor_value))

        return damage
    end

    -- credits: https://neverlose.cc/market/viewscript_os?id=zG8686
    bomb.get_damage = function ()
        local lp = c_entity.new(entity.get_local_player())
        local from_player = lp
        local armor_value = from_player.m_ArmorValue
        local info = entity.get_all("CPlantedC4") 
        for index, value in ipairs(info) do
            return calculate_damage(from_player, value, armor_value)
        end
        
    end
    return bomb
end
local renderer = require("gamesense/surface")
local bomb = require("bomb")
local pui = require("gamesense/pui")
local vector = require("vector")
local images = require("gamesense/images")
local base64 = require("gamesense/base64")
FONTFLAG = {
    NONE            = 0,
    ITALIC          = 0x001,
    UNDERLINE       = 0x002,
    STRIKEOUT       = 0x004,
    SYMBOL          = 0x008,
    ANTIALIAS       = 0x010,
    GAUSSIANBLUR    = 0x020,
    ROTARY          = 0x040,
    DROPSHADOW      = 0x080,
    ADDITIVE        = 0x100,
    OUTLINE         = 0x200,
    CUSTOM          = 0x400,
    BITMAP          = 0x800
}
local STRTONUM = {
	THIN			= 100,
	EXTRALIGHT	  = 200,
	LIGHT		   = 300,
	NORMAL		  = 400,
	MEDIUM		  = 500,
	SEMIBOLD		= 600,
	BOLD			= 700,
	EXTRABOLD   = 800,
	HEAVY		   = 900,
}

local screen = vector(client.screen_size())
local dpi_scale = screen.y / 1440
if dpi_scale < 1 then
    dpi_scale = 1
end



local Lua = {
    Menu = {
        Tabs = {
            Lua_A = pui.group("LUA","A"),
            Lua_B = pui.group("LUA","B")
        },
        Drag = {}
    },
    render = {
        fonts = {
            bomb_text = renderer.create_font("Verdana", 13 * dpi_scale, STRTONUM.NORMAL, {FONTFLAG.ANTIALIAS}),
        },
        images = {
            bomb_icon = images.load(base64.decode(""))
        },
    }
}
local draggable = {}
local mouse = { x = 0, y = 0, last_x = 0, last_y = 0, down = false, last_down = false }
local Drag = {}
Drag.__index = Drag

function Drag:new(name, default_x, default_y, resolution)
    resolution = resolution or 100000
    local screen_width, screen_height = client.screen_size()

    local x_default = math.floor(default_x / screen_width * resolution + 0.5)
    local y_default = math.floor(default_y / screen_height * resolution + 0.5)

    local x_slider_name = name .. "_x_slider"
    local y_slider_name = name .. "_y_slider"

    Lua.Menu.Drag[x_slider_name] = Lua.Menu.Tabs.Lua_A:slider(name.." X", 0, resolution, x_default)
    Lua.Menu.Drag[y_slider_name] = Lua.Menu.Tabs.Lua_A:slider(name.." Y", 0, resolution, y_default)
    Lua.Menu.Drag[x_slider_name]:set_visible(false)
    Lua.Menu.Drag[y_slider_name]:set_visible(false)

    local self = setmetatable({
        name = name,
        x_reference = Lua.Menu.Drag[x_slider_name],
        y_reference = Lua.Menu.Drag[y_slider_name],
        resolution = resolution,
        drag_active = false,
        menu = Lua.Menu.Drag
    }, Drag)

    return self
end

function Drag:get(width, height)
    local screen_width, screen_height = client.screen_size()
    local cx = self.x_reference:get() / self.resolution * screen_width
    local cy = self.y_reference:get() / self.resolution * screen_height
    return cx - (width and width / 2 or 0), cy - (height and height / 2 or 0)
end

function Drag:set(left_x, top_y, width, height)
    local screen_width, screen_height = client.screen_size()
    local cx = left_x + (width / 2)
    local cy = top_y + (height / 2)
    if globals.frametime() > 0 or globals.absoluteframetime() > 0 then 
        self.x_reference:set(cx / screen_width * self.resolution)
        self.y_reference:set(cy / screen_height * self.resolution)
    end
end

function Drag:update(width, height, clamp)
    local screen_width, screen_height = client.screen_size()
    local left_x, top_y = self:get(width, height)
    
    mouse.last_x, mouse.last_y = mouse.x, mouse.y
    mouse.x, mouse.y = ui.mouse_position()
    mouse.last_down = mouse.down
    mouse.down = client.key_state(0x1)
    local right_down = client.key_state(0x2)
    local ui_open = ui.is_menu_open()

    if ui_open then
        if right_down and
        mouse.x >= left_x and mouse.x <= left_x + width and
        mouse.y >= top_y  and mouse.y <= top_y + height then
            left_x = (screen_width - width) / 2
            self:set(left_x, top_y, width, height)
        end
        if not self.drag_active and mouse.down and
        mouse.x >= left_x and mouse.x <= left_x + width and
        mouse.y >= top_y  and mouse.y <= top_y + height then
            self.drag_active = true
            self.drag_offset_x = mouse.x - left_x
            self.drag_offset_y = mouse.y - top_y
        elseif not mouse.down then
            self.drag_active = false
        end
        if self.drag_active then
            left_x = mouse.x - self.drag_offset_x
            top_y  = mouse.y - self.drag_offset_y

            if clamp ~= false then
                left_x = math.max(0, math.min(screen_width - width, left_x))
                top_y  = math.max(0, math.min(screen_height - height, top_y))
            end
        end
    else
        self.drag_active = false
    end

    self:set(left_x, top_y, width, height)

    if self.drag_active then
        local r,g,b,a = 0,0,0,175
        -- top
        renderer.rectangle(0, 0, screen_width, top_y, r, g, b, a)
        -- bottom
        renderer.rectangle(0, top_y + height, screen_width, screen_height - (top_y + height), r, g, b, a)
        -- left
        renderer.rectangle(0, top_y, left_x, height, r, g, b, a)
        -- right
        renderer.rectangle(left_x + width, top_y, screen_width - (left_x + width), height, r, g, b, a)
    end

    return left_x, top_y
end



function draggable:get_ui_tables()
    return self.menu
end

draggable.Drag = Drag

local bomb_info = draggable.Drag:new("Bomb Info", screen.x /2, screen.y/2 + 20)
client.set_event_callback("paint",function ()
    local w,h = 180,58
    local pic_size = h
    local font = Lua.render.fonts.bomb_text
    local x,y = bomb_info:update(w,h)
    local r,g,b,a = pui.reference("MISC", "Settings", "Menu color"):get()
    if (bomb.is_planted() == 1 or  bomb.get_is_planting()) or ui.is_menu_open() then
        local timer = bomb.get_time() or ""
        local site = bomb.get_site() or ""
        local damage = bomb.get_damage() or 0
        local damage_text = "DMG: "..tostring(damage)
        if entity.get_prop(entity.get_local_player(),"m_iHealth") < damage then
            damage_text = "DMG: FATAL"
        end
        local defusing = bomb.is_getting_defused() or false
        local planting =  bomb.get_is_planting() or false
        local defusing_text = "Defusing: "..tostring(defusing)
        local site_text = "Site: "..tostring(site)
        local timer_text = "Timer: "..tostring(timer)
        if defusing then
            timer_text = "Timer: "..tostring(bomb.get_defuse_time())
        end
        if planting then
            timer_text = "Timer: "..tostring(bomb.get_planting_time())
        end
        local timer_size = vector(renderer.get_text_size(font,timer_text))
        local site_size = vector(renderer.get_text_size(font,site_text))
        renderer.draw_filled_rect(x, y, w, h,0, 0, 0, 255)
        local texts = {defusing_text, timer_text, site_text,damage_text}
        local spacing = 13
        local start_offset = -20

        for i, text in ipairs(texts) do
            local offset = start_offset + (i - 1) * spacing
            renderer.draw_text(x, y + h/2 - site_size.y/2 + offset, r, g, b, a, font, text)
        end
        Lua.render.images.bomb_icon:draw(x + w/2 + pic_size/2, y, pic_size, pic_size, 255,255,255,255, true,"f")
    end
end)

client.set_event_callback("setup_command",function (cmd)
    if ui.is_menu_open() then
        cmd.in_attack = false
        cmd.in_attack2 = false
    end
